actions.script:
import com.prowidesoftware.swift.model.SwiftMessage as ProwideSwiftMessage
def sm = ProwideSwiftMessage.parse(raw.rawContent)
def tag21 = sm.getBlock4()?.getTagValue("21")?.trim()
def tag20 = sm.getBlock4()?.getTagValue("20")?.trim()
def tag30 = sm.getBlock4()?.getTagValue("30")?.trim()
def tag32b = sm.getBlock4()?.getTagValue("32B")
def tag77j = sm.getBlock4()?.getTagValue("77J")
def tag79 = sm.getBlock4()?.getTagValue("79")
def senderBic = sm.getBlock1()?.getLogicalTerminal()?.substring(0, 8) ?: "UNKNOWN"
def msgType = sm.getType()

// Parse claim amount from Tag 32B (format: CCYAMOUNT e.g. "USD45000,00")
def claimAmount = null; def claimCurrency = null
if (tag32b && tag32b.length() > 3) {
    claimCurrency = tag32b.substring(0, 3)
    try {
        claimAmount = new BigDecimal(tag32b.substring(3).replace(",", "."))
    } catch (Exception e) {
        ec.logger.warn("Failed to parse amount from Tag 32B: ${tag32b}")
    }
}

// Correlation Logic
def correlationStatus = "CORR_ORPHANED"
def inboxStatus = "INBOX_ORPHANED"
def orphanReason = null
def instrumentId = null
def amendmentId = null

if (tag21) {
    def instruments = ec.entity.find("trade.TradeInstrument")
        .condition("instrumentRef", tag21).list()
    if (instruments.size() == 1) {
        instrumentId = instruments[0].instrumentId
        correlationStatus = "CORR_AUTO_MATCH"
        inboxStatus = "INBOX_UNREAD"

        // Sub-correlation: MT 730/799 — match to amendment via Tag 30
        if (msgType in ["730", "799"] && tag30 && instrumentId) {
            def amendments = ec.entity.find("trade.importlc.ImportLcAmendment")
                .condition("instrumentId", instrumentId).list()
            def parsedDate = tag30 
            def matched = amendments.find { amd ->
                def amdDate = amd.amendmentDate?.format("yyMMdd")
                return amdDate == parsedDate
            }
            if (matched) amendmentId = matched.amendmentId
        }
    } else if (instruments.size() == 0) {
        // Try matching amendment directly by transactionRef (common for MT 799/730)
        def amendments = ec.entity.find("trade.importlc.ImportLcAmendment")
            .condition("transactionRef", tag21).list()
        if (amendments.size() == 1) {
            amendmentId = amendments[0].amendmentId
            instrumentId = amendments[0].instrumentId
            correlationStatus = "CORR_AUTO_MATCH"
            inboxStatus = "INBOX_UNREAD"
        } else {
            orphanReason = "NO_MATCH_FOUND"
        }
    } else {
        orphanReason = "AMBIGUOUS_REF"
    }
} else {
    orphanReason = "NO_TAG21"
}

def securityWarning = (msgType == "999") ? "Y" : "N"
def narrative = tag79 ?: tag77j

def params = [
    rawMessageId: rawMessageId?.toString(), 
    instrumentId: instrumentId?.toString(),
    amendmentId: amendmentId?.toString(), 
    messageType: msgType,
    senderBic: senderBic, senderReference: tag20,
    relatedReference: tag21, narrativeText: narrative,
    claimAmount: claimAmount, claimCurrency: claimCurrency,
    receivedTimestamp: ec.user.nowTimestamp,
    inboxStatusEnumId: inboxStatus,
    correlationStatusEnumId: correlationStatus,
    orphanReason: orphanReason,
    securityWarningFlag: securityWarning
]

ec.logger.info("DEBUG_PRINT: Creating TradeInboxItem with params: ${params}")
try {
    inboxItemId = ec.entity.makeValue("trade.swift.TradeInboxItem").setAll(params).setSequencedIdPrimary().create().inboxItemId
} catch (Throwable t) {
    ec.logger.error("!!! BOMB in create TradeInboxItem: " + t.getMessage(), t)
    throw t
}

// Auto-trigger actions for AUTO_MATCH
if (correlationStatus == "CORR_AUTO_MATCH" && inboxItemId) {
    ec.artifactExecution.disableAuthz()
    def item = ec.entity.find("trade.swift.TradeInboxItem").condition("inboxItemId", inboxItemId).one()
    ec.logger.info("DEBUG_PRINT: Auto-triggering action for ${msgType} on inboxItem ${inboxItemId}")
    try {
        if (msgType == "730") {
            def sm30 = ProwideSwiftMessage.parse(raw.rawContent)
            def tag20_30 = sm30.getBlock4()?.getTagValue("20")?.trim()
            def tag30_30 = sm30.getBlock4()?.getTagValue("30")?.trim()
            def advisedDate = null
            if (tag30_30) {
                def localDate = java.time.LocalDate.parse(tag30_30, java.time.format.DateTimeFormatter.ofPattern("yyMMdd"))
                advisedDate = java.sql.Date.valueOf(localDate)
            }
            if (item.amendmentId) {
                def amendment = ec.entity.find("trade.importlc.ImportLcAmendment").condition("amendmentId", item.amendmentId).one()
                amendment.isAdvisedToBeneficiary = 'Y'; amendment.advisedToBeneficiaryDate = advisedDate; amendment.update()
            } else if (item.instrumentId) {
                def lc = ec.entity.find("trade.importlc.ImportLetterOfCredit").condition("instrumentId", item.instrumentId).one()
                lc.isAdvised = 'Y'; lc.advisedDate = advisedDate; lc.advisingBankReference = tag20_30; lc.update()
            }
            item.actionTaken = 'LC_DELIVERY_CONFIRMED'; item.inboxStatusEnumId = 'INBOX_PROCESSED'; item.processedTimestamp = ec.user.nowTimestamp; item.update()
        }

        if (msgType == "799") {
            if (item.amendmentId && (raw.rawContent.toUpperCase().contains('ACKNOWLEDGE') || raw.rawContent.toUpperCase().contains('ACCEPT'))) {
                ec.service.sync().name("trade.importlc.ImportLcServices.accept#Amendment").parameter("amendmentId", item.amendmentId).call()
                item.actionTaken = 'AMENDMENT_AUTO_ACCEPTED_799'; item.inboxStatusEnumId = 'INBOX_PROCESSED'; item.processedTimestamp = ec.user.nowTimestamp; item.update()
            }
        }

        if (msgType == "750") {
            def presResult = ec.service.sync().name("trade.TradeCommonServices.create#Presentation").parameters([
                instrumentId: item.instrumentId, claimAmount: item.claimAmount, claimCurrency: item.claimCurrency,
                presentingBankRef: item.senderReference, isDiscrepant: 'Y', applicantDecisionEnumId: 'PENDING',
                presentationStatusId: 'PRES_RECEIVED', sourceChannel: 'INBOUND']).call()
            ec.service.sync().name("trade.importlc.ImportLcServices.update#ImportLetterOfCredit").parameters([instrumentId: item.instrumentId, businessStateId: 'LC_DOC_RECEIVED']).call()
            item.presentationId = presResult.presentationId; item.actionTaken = 'SPAWN_PRESENTATION_750'; item.inboxStatusEnumId = 'INBOX_PROCESSED'; item.processedTimestamp = ec.user.nowTimestamp; item.update()
        }

        if (msgType == "754") {
            def presResult = ec.service.sync().name("trade.TradeCommonServices.create#Presentation").parameters([
                instrumentId: item.instrumentId, claimAmount: item.claimAmount, claimCurrency: item.claimCurrency,
                presentingBankRef: item.senderReference, isDiscrepant: 'N', applicantDecisionEnumId: 'WAIVED',
                presentationStatusId: 'PRES_COMPLIANT', sourceChannel: 'INBOUND']).call()
            ec.service.sync().name("trade.importlc.ImportLcServices.update#ImportLetterOfCredit").parameters([instrumentId: item.instrumentId, businessStateId: 'LC_ACCEPTED']).call()
            item.presentationId = presResult.presentationId; item.actionTaken = 'PRESENTATION_AUTO_SPAWNED_754'; item.inboxStatusEnumId = 'INBOX_PROCESSED'; item.processedTimestamp = ec.user.nowTimestamp; item.update()
        }

        if (msgType == "742") {
            def recons = ec.entity.find("trade.importlc.NostroReconciliation").condition([instrumentId: item.instrumentId, matchStatusEnumId: 'RECON_PENDING']).list()
            if (recons) {
                def recon = recons[0]
                if (item.claimAmount <= recon.expectedAmount) {
                    recon.matchStatusEnumId = 'RECON_MATCHED'; recon.matchedAmount = item.claimAmount; recon.update()
                    item.actionTaken = 'REIMBURSEMENT_AUTO_MATCHED'
                } else {
                    recon.matchStatusEnumId = 'RECON_EXCEPTION'; recon.update()
                    item.actionTaken = 'REIMBURSEMENT_EXCEPTION_OVER_LIMIT'
                }
                item.inboxStatusEnumId = 'INBOX_PROCESSED'; item.processedTimestamp = ec.user.nowTimestamp; item.update()
            } else {
                item.inboxStatusEnumId = 'INBOX_ORPHANED'; item.orphanReason = 'NO_PENDING_RECON'; item.update()
            }
        }
    } catch (Throwable t) {
        ec.logger.error("!!! BOMB in action trigger for ${msgType}: " + t.getMessage(), t)
        throw t
    }
}
